query:
-- 統計測試員工數量
SELECT COUNT(*) as test_workers FROM workers 
WHERE name LIKE '%測試%' OR name LIKE '%TEST%' OR name LIKE '%test%' OR name LIKE '%核心流程%';

-- 統計測試客戶數量
SELECT COUNT(*) as test_clients FROM clients 
WHERE name LIKE '%測試%' OR name LIKE '%TEST%' OR name LIKE '%test%' OR name LIKE '%核心流程%';

-- 統計測試需求單數量
SELECT COUNT(*) as test_demands FROM demands 
WHERE note LIKE '%測試%' OR note LIKE '%TEST%' OR note LIKE '%test%' OR note LIKE '%核心流程%';

-- 統計測試指派數量
SELECT COUNT(*) as test_assignments FROM assignments 
WHERE workerId IN (
  SELECT id FROM workers WHERE name LIKE '%測試%' OR name LIKE '%TEST%' OR name LIKE '%test%' OR name LIKE '%核心流程%'
);

-- 統計測試排班數量
SELECT COUNT(*) as test_availability FROM availability 
WHERE workerId IN (
  SELECT id FROM workers WHERE name LIKE '%測試%' OR name LIKE '%TEST%' OR name LIKE '%test%' OR name LIKE '%核心流程%'
);

